import React, { useState } from 'react';
import {
    CDropdown,
    CDropdownToggle,
    CDropdownMenu,
    CDropdownItem,
} from '@coreui/react';
import { cilAccountLogout, cilBell, cilCommentSquare, cilCreditCard, cilEnvelopeOpen, cilFile, cilSettings, cilTask, cilUser } from '@coreui/icons';
import { CBadge, CDropdownDivider, CDropdownHeader } from '@coreui/react-pro';
import CIcon from '@coreui/icons-react';

const ProfileDropdown = () => {
    const [visible, setVisible] = useState(false);

    const handleToggle = () => {
        setVisible((prevVisible) => !prevVisible);
    };

    return (
        // <CDropdown
        //     alignment="end"
        //     visible={visible}
        //     onVisibleChange={setVisible}
        //     className="profile-dropdown"
        // >
        //     <CDropdownToggle
        //         className="p-0 border-0 bg-transparent"
        //         caret={false}
        //         onClick={handleToggle}
        //     >

                // <img
                //     src="https://ui-avatars.com/api/?name=Dheeraj+Khanna"
                //     alt="User"
                //     className="rounded-circle"
                //     width="36"
                //     height="36"
                //     style={{ objectFit: 'cover', cursor: 'pointer' }}
                // />



        //     </CDropdownToggle>

        //     <CDropdownMenu className={`pt-0 ${visible ? 'show' : ''}`}>
        //         <CDropdownItem href="#">Profile</CDropdownItem>
        //         <CDropdownItem href="#">Settings</CDropdownItem>
        //         <CDropdownItem href="#">Logout</CDropdownItem>
        //     </CDropdownMenu>
        // </CDropdown>

        <CDropdown variant="nav-item">
            <CDropdownToggle  className="p-0 border-0 bg-transparent" caret={false}>
                <img
                    src="https://ui-avatars.com/api/?name=Dheeraj+Khanna"
                    alt="User"
                    className="rounded-circle"
                    width="36"
                    height="36"
                    style={{ objectFit: 'cover', cursor: 'pointer' }}
                />
            </CDropdownToggle>
            <CDropdownMenu className="pt-0" placement="bottom-end">
                <CDropdownHeader className="bg-light fw-semibold py-2">Account</CDropdownHeader>
                <CDropdownItem href="#">
                    <CIcon icon={cilBell} className="me-2" />
                    Updates
                    <CBadge color="info" className="ms-2">
                        42
                    </CBadge>
                </CDropdownItem>
                <CDropdownItem href="#">
                    <CIcon icon={cilEnvelopeOpen} className="me-2" />
                    Messages
                    <CBadge color="success" className="ms-2">
                        42
                    </CBadge>
                </CDropdownItem>
                <CDropdownItem href="#">
                    <CIcon icon={cilTask} className="me-2" />
                    Tasks
                    <CBadge color="danger" className="ms-2">
                        42
                    </CBadge>
                </CDropdownItem>
                <CDropdownItem href="#">
                    <CIcon icon={cilCommentSquare} className="me-2" />
                    Comments
                    <CBadge color="warning" className="ms-2">
                        42
                    </CBadge>
                </CDropdownItem>
                <CDropdownHeader className="bg-light fw-semibold py-2">Settings</CDropdownHeader>
                <CDropdownItem href="#">
                    <CIcon icon={cilUser} className="me-2" />
                    Profile
                </CDropdownItem>
                <CDropdownItem href="#">
                    <CIcon icon={cilSettings} className="me-2" />
                    Settings
                </CDropdownItem>
                <CDropdownItem href="#">
                    <CIcon icon={cilCreditCard} className="me-2" />
                    Payments
                    <CBadge color="secondary" className="ms-2">
                        42
                    </CBadge>
                </CDropdownItem>
                <CDropdownItem href="#">
                    <CIcon icon={cilFile} className="me-2" />
                    Projects
                    <CBadge color="primary" className="ms-2">
                        42
                    </CBadge>
                </CDropdownItem>
                <CDropdownDivider />
                <CDropdownItem >
                    <CIcon icon={cilAccountLogout} className="me-2" />
                    Logout
                </CDropdownItem>
            </CDropdownMenu>
        </CDropdown>
    );
};

export default ProfileDropdown;
